// Parse XML e extrair dados
const input = $input.first().json;
let xmlData;

try {
  const xmlString = input.xml_ref || '';
  if (!xmlString) {
    throw new Error('XML data not provided');
  }

  // Parse XML simples (assumindo formato <xjx><cmd>...)
  const cmdPattern = /<cmd[^>]*t="([^"]+)"[^>]*>([^<]*)<\/cmd>/g;
  const parsedData = {};
  let match;

  while ((match = cmdPattern.exec(xmlString)) !== null) {
    const key = match[1];
    const value = match[2].trim();

    if (key && key !== 'no-set') {
      parsedData[key] = value;
    }
  }

  // Remover campos específicos conforme código Python
  delete parsedData['estoque_pedido'];
  delete parsedData['bloquear_edicao_cliente'];

  xmlData = parsedData;
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'nf_service_info',
    event: 'xml_parse_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'XML parsing failed', details: error.message }
  };
}

// Enriquecimento básico com centro de custo
let ccRef = '-1';
if (xmlData.obs_interno_pedido) {
  const ccMatch = xmlData.obs_interno_pedido.match(/CC[:\s]*([A-Z0-9]+)/i);
  if (ccMatch) {
    ccRef = ccMatch[1];
  }
}

// Preparar dados para inserção
const serviceData = {
  id_servico: xmlData.id_servico || '',
  obs_interno_pedido: xmlData.obs_interno_pedido || '',
  obs_pedido: xmlData.obs_pedido || '',
  numero_processo: xmlData.numero_processo || '',
  condicao_pagamento: xmlData.condicao_pagamento || '',
  condicao_pagamento_id: xmlData.condicao_pagamento_id || '',
  valor_iss: xmlData.valor_iss || '',
  aliq_iss: xmlData.aliq_iss || '',
  valor_ir: xmlData.valor_ir || '',
  aliq_ir: xmlData.aliq_ir || '',
  valor_contribuicao: xmlData.valor_contribuicao || '',
  aliq_contribuicao: xmlData.aliq_contribuicao || '',
  valor_pis: xmlData.valor_pis || '',
  aliq_pis: xmlData.aliq_pis || '',
  valor_cofins: xmlData.valor_cofins || '',
  aliq_cofins: xmlData.aliq_cofins || '',
  valor_material: xmlData.valor_material || '',
  valor_tributos_mun: xmlData.valor_tributos_mun || '',
  valor_aliq_tributos_mun: xmlData.valor_aliq_tributos_mun || '',
  valor_tributos: xmlData.valor_tributos || '',
  valor_aliq_tributos: xmlData.valor_aliq_tributos || '',
  valor_imposto: xmlData.valor_imposto || '',
  valor_aliquota: xmlData.valor_aliquota || '',
  valor_base_calculo: xmlData.valor_base_calculo || '',
  valor_condicionado: xmlData.valor_condicionado || '',
  valor_incondicionado: xmlData.valor_incondicionado || '',
  valor_deducoes: xmlData.valor_deducoes || '',
  itemLista_servico: xmlData.itemLista_servico || '',
  valor_total_nota: xmlData.valor_total_nota || '',
  valor_total_servicos: xmlData.valor_total_servicos || '',
  desc_servicos: xmlData.desc_servicos || '',
  serie_nota: xmlData.serie_nota || '',
  id_pedido: xmlData.id_pedido || '',
  vendedor_pedido_id: xmlData.vendedor_pedido_id || '',
  vendedor_pedido: xmlData.vendedor_pedido || '',
  ultrapassar_limite_credito: xmlData.ultrapassar_limite_credito || '',
  contas_pedido: xmlData.contas_pedido || '',
  id_cliente: xmlData.id_cliente || '',
  nome_cliente: xmlData.nome_cliente || '',
  cc_ref: ccRef
};

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'data_parse_success',
  id_servico: serviceData.id_servico,
  cc_ref: ccRef,
  level: 'info'
}));

return { serviceData };

// Sucesso
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'upsert_success',
  affected_rows: result.affectedRows || 0,
  level: 'info'
}));

return {
  statusCode: 200,
  body: { 
    ok: true, 
    message: 'Data extracted, cleaned, and converted to DataFrame successfully' 
  }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'nf_service_info',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process service info' }
};
